        "expectedResponse": "Autotroph: Plant; Heterotroph: Human/Animal.",
        "answerPoints": [
          "Correct identification of examples"
        ]
      }
    ],
    "commonMisconceptionsDetailed": [
      {
        "misconception": "Students think plants do not need food because they don't eat like animals.",
        "correction": "Clarify that plants make their own food (photosynthesis) which is a form of nutrition. They still require energy and nutrients."
      },
      {
        "misconception": "Confusing 'breathing' with 'respiration'.",
        "correction": "Explain breathing is physical movement of air; respiration is the chemical process inside cells to release energy from food."
      }
    ],
    "differentiation": {
      "slowLearners": [
        "Use simple analogies like 'eating' and 'breathing'.",
        "Focus on memorizing the 4 names of life processes first.",
        "Provide a printed list with pictures."
      ],
      "averageLearners": [
